(()=>{var n=class{formatSiteTime=()=>{let t=new Date(window.config?.siteTime),o=document.querySelector(".run-times"),e=document.querySelector(".site-time span:not(.run-times)");if(!o||Number.isNaN(t.getTime()))return;let i=Math.floor((new Date-t)/1e3),s=Math.floor(i/86400),r=Math.floor(i%86400/3600),w=Math.floor(i%3600/60),a=i%60;e&&(e.textContent="Runing",e.classList.remove("d-none")),o.textContent=`${s}\u5929${String(r).padStart(2,"0")}\u65F6${String(w).padStart(2,"0")}\u5206${String(a).padStart(2,"0")}\u79D2`};patchSiteTime=(t=20)=>{if(!window.fixit||!window.config?.siteTime){t>0&&window.setTimeout(()=>this.patchSiteTime(t-1),100);return}window.clearInterval(window.fixit.siteTime),window.fixit.getSiteTime=this.formatSiteTime,window.fixit.getSiteTime(),window.fixit.siteTime=window.setInterval(window.fixit.getSiteTime,500)};init(){return this.patchSiteTime(),this}};window.fixitBlog=new n,document.addEventListener("DOMContentLoaded",()=>{window.fixitBlog.init()});})();
